cd /tmp/sv-5a53de0f9aeb4b16ba28b12ff492dadb/moderate-version-conflicts && dotnet package list --format json > after-cpm-packages.json 2>&1 && python3 -c "
import json
with open('baseline-packages.json') as f: baseline = json.load(f)
with open('after-cpm-packages.json') as f: after = json.load(f)

def extract(data):
    result = {}
    for p in data['projects']:
        name = p['path'].split('/')[-2]
        pkgs = {}
        for fw in p['frameworks']:
            for pkg in fw.get('topLevelPackages', []):
                pkgs[pkg['id']] = pkg['resolvedVersion']
        result[name] = pkgs
    return result

b, a = extract(baseline), extract(after)
print('Package comparison (baseline -> after):')
for proj in sorted(set(list(b.keys()) + list(a.keys()))):
    bp, ap = b.get(proj, {}), a.get(proj, {})
    for pkg in sorted(set(list(bp.keys()) + list(ap.keys()))):
        bv, av = bp.get(pkg, 'N/A'), ap.get(pkg, 'N/A')
        status = 'CHANGED' if bv != av else 'OK'
        if status == 'CHANGED':
            print(f'  [{status}] {proj}/{pkg}: {bv} -> {av}')
print('Done.')
"

